457	// Create adds a new bead. Assigns defaults, validates, then persists.
458	func (s *Store) Create(b *Bead) error {
459		now := time.Now().UTC()
460		if b.ID == "" {
461			id, err := s.GenID()
462			if err != nil {
463				return err
464			}
465			b.ID = id
466		}
467		if b.IssueType == "" {
468			b.IssueType = DefaultType
469		}
470		if b.Status == "" {
471			// Creation is not a transition; the only status write that does not go
472			// through transitionLifecycleInPlace (TD-031 §3 transition matrix).
473			b.Status = DefaultStatus
474		}
475		b.CreatedAt = now
476		b.UpdatedAt = now
477	
478		// Validate after defaults are applied so hooks see final state
479		if err := s.validateBead(b); err != nil {
480			return err
481		}
482		// Story 15: an operator-prompt bead's execution may not create another
483		// operator-prompt bead. The execute-bead harness exports the actor's
484		// issue_type via DDX_ACTOR_ISSUE_TYPE; absent the env, the guard is a
485		// no-op (e.g. direct CLI use by a human operator).
486		if err := OperatorPromptMutationGuard(os.Getenv("DDX_ACTOR_ISSUE_TYPE"), b.IssueType); err != nil {
487			return err
488		}
489		// Run create hook
490		if err := s.runHook("validate-bead-create", b); err != nil {
491			return err
492		}
493	
494		return s.WithLock(func() error {
495			beads, _, err := s.readAllLatestRaw()
496			if err != nil {
497				return err
498			}
499			// Reject duplicate IDs
500			for _, e := range beads {
501				if e.ID == b.ID {
502					return fmt.Errorf("bead: duplicate id: %s", b.ID)
503				}
504			}
505			// Validate deps reference existing beads
506			depIDs := b.DepIDs()
507			if len(depIDs) > 0 {
508				existing := make(map[string]bool)
509				for _, e := range beads {
510					existing[e.ID] = true
511				}
512				for _, dep := range depIDs {
513					if !existing[dep] {
514						return fmt.Errorf("bead: dependency not found: %s", dep)
515					}
516				}
517			}
518			beads = append(beads, *b)
519			return s.WriteAll(beads)
520		})
521	}
522	
523	// Get retrieves a bead by ID.
524	func (s *Store) Get(id string) (*Bead, error) {
525		beads, err := s.ReadAll()
526		if err != nil {
527			return nil, err
528		}
529		for _, b := range beads {
530			if b.ID == id {
531				return &b, nil
532			}
533		}
534		return nil, fmt.Errorf("bead: not found: %s", id)
535	}
536	
537	// Update modifies a bead by ID. The mutate function receives a pointer to
538	// modify, but persisted lifecycle status changes must use TransitionLifecycle.
539	func (s *Store) Update(id string, mutate func(*Bead)) error {
540		return s.updateBead(id, false, func(b *Bead) error {
541			mutate(b)
542			return nil
543		})
544	}
545	
546	func (s *Store) updateBead(id string, allowStatusChange bool, mutate func(*Bead) error) error {
547		return s.WithLock(func() error {
548			beads, _, err := s.readAllLatestRaw()
549			if err != nil {
550				return err
551			}
552			found := false
553			for i := range beads {
554				if beads[i].ID == id {
555					beforeStatus := beads[i].Status
556					if mutate != nil {
557						if err := mutate(&beads[i]); err != nil {
558							return err
559						}
560					}
561					if !allowStatusChange && beads[i].Status != beforeStatus {
562						return fmt.Errorf("bead: lifecycle status change %s -> %s requires Store.TransitionLifecycle", beforeStatus, beads[i].Status)
563					}
564					beads[i].UpdatedAt = time.Now().UTC()
565					// Core validation after mutation
566					if err := s.validateBead(&beads[i]); err != nil {
567						return err
568					}
569					// Run update hook
570					if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
571						return err
572					}
573					found = true
574					break
575				}
576			}
577			if !found {
578				return fmt.Errorf("bead: not found: %s", id)
579			}
580			return s.WriteAll(beads)
581		})
582	}
583	
584	// TransitionLifecycle validates and persists one bead lifecycle status
585	// transition. Callers may provide a mutator for metadata that must land
586	// atomically with the status write.
587	func (s *Store) TransitionLifecycle(id string, status string, opts LifecycleTransitionOptions, mutate func(*Bead) error) error {
588		return s.updateBead(id, true, func(b *Bead) error {
589			if err := transitionLifecycleInPlace(b, status, opts); err != nil {
590				return err
591			}
592			if mutate != nil {
593				return mutate(b)
594			}
595			return nil
596		})
597	}
598	
599	// SetLifecycleStatus validates and persists a lifecycle status transition.
600	func (s *Store) SetLifecycleStatus(id string, status string, opts LifecycleTransitionOptions) error {
601		return s.TransitionLifecycle(id, status, opts, nil)
602	}
603	
604	// UpdateWithLifecycleStatus atomically applies non-status field mutations and
605	// a validated lifecycle status transition.
606	func (s *Store) UpdateWithLifecycleStatus(id string, status string, opts LifecycleTransitionOptions, mutate func(*Bead) error) error {
607		return s.updateBead(id, true, func(b *Bead) error {
608			beforeStatus := b.Status
609			if mutate != nil {
610				if err := mutate(b); err != nil {
611					return err
612				}
613			}
614			if b.Status != beforeStatus {
615				return fmt.Errorf("bead: UpdateWithLifecycleStatus mutator changed lifecycle status directly")
616			}
617			return transitionLifecycleInPlace(b, status, opts)
618		})
619	}
620	
621	func transitionLifecycleInPlace(b *Bead, status string, opts LifecycleTransitionOptions) error {
622		from := b.Status
623		if err := ValidateLifecycleTransition(from, status, opts); err != nil {
624			return fmt.Errorf("bead: lifecycle transition %s -> %s rejected: %w", from, status, err)
625		}
626		b.Status = status
627		applyLifecycleTransitionMetadata(b, status, opts)
628		return nil
629	}
630	
631	const ExtraLifecycleExternalBlockerReason = "lifecycle-external-blocker-reason"
632	
633	func applyLifecycleTransitionMetadata(b *Bead, status string, opts LifecycleTransitionOptions) {
634		if b.Extra == nil {
635			b.Extra = make(map[string]any)
636		}
637		if status == StatusBlocked {
638			if reason := strings.TrimSpace(opts.ExternalBlockerReason); reason != "" {
