883	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
884	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
885	// DDx-authored beads always round-trip through `bd import`. Empirically
886	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
887	const MaxFieldBytes = 65535
888	
889	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
890	// need to preserve the full payload should persist it to a sidecar artifact
891	// and store a path reference in the field; this function is the defense-in-
892	// depth cap for code paths that don't. Returns the input unchanged when it
893	// fits; otherwise returns head+tail truncation with a byte-count marker.
894	func capFieldBytes(s string) string {
895		if len(s) <= MaxFieldBytes {
896			return s
897		}
898		// Reserve a marker that always fits; keep head heavy (2/3) so
899		// human-readable context is preserved for the common short-rationale case.
900		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
901		budget := MaxFieldBytes - len(marker)
902		if budget <= 0 {
903			return s[:MaxFieldBytes]
904		}
905		head := (budget * 2) / 3
906		tail := budget - head
907		return s[:head] + marker + s[len(s)-tail:]
908	}
