910	// Cancel-marker keys on Bead.Extra. ADR-022 §Cancel SLA: an operator-initiated
911	// cancel writes cancel-requested:true; the worker that honors the cancel writes
912	// cancel-honored:true alongside it.
913	const (
914		ExtraCancelRequested = "cancel-requested"
915		ExtraCancelHonored   = "cancel-honored"
916	)
917	
918	// RequestCancel writes Extra[cancel-requested]=true on the bead. Idempotent:
919	// if cancel-honored is already set the call is a silent no-op (the prior cancel
920	// was already consumed). Returns true when the marker is now set on the bead
921	// (either by this call or a prior one).
922	func (s *Store) RequestCancel(id string) (bool, error) {
923		var set bool
924		err := s.Update(id, func(b *Bead) {
925			if b.Extra == nil {
926				b.Extra = make(map[string]any)
927			}
928			if isExtraTrue(b.Extra[ExtraCancelHonored]) {
929				set = isExtraTrue(b.Extra[ExtraCancelRequested])
930				return
931			}
932			b.Extra[ExtraCancelRequested] = true
933			set = true
934		})
935		return set, err
936	}
