954	// MarkCancelHonored sets Extra[cancel-honored]=true. Called by the worker once
955	// it has aborted at the next safe point in response to a cancel request.
956	func (s *Store) MarkCancelHonored(id string) error {
957		return s.Update(id, func(b *Bead) {
