1021	// Events returns the bead's evidence history in insertion order. Reads are
1022	// transparent across storage shapes: inline Extra["events"] for active beads,
1023	// or the externalized sidecar referenced by Extra[events_attachment] once the
1024	// bead has been closed.
1025	func (s *Store) Events(id string) ([]BeadEvent, error) {
1026		b, err := s.Get(id)
1027		if err != nil {
