1029		}
1030		events, err := s.eventsForBead(b)
1031		if err != nil {
1032			return nil, err
1033		}
1034		if len(events) == 0 {
1035			return []BeadEvent{}, nil
1036		}
1037		out := make([]BeadEvent, len(events))
1038		copy(out, events)
1039		return out, nil
