1212	// CloseWithEvidence sets a bead's status to closed and records agent session evidence.
1213	// sessionID is the agent session that completed the work.
1214	// commitSHA is the exact closing commit SHA when it is known.
1215	//
1216	// Enforces ClosureGate (ddx-e30e60a9): a bead cannot transition to closed
1217	// via this path without a terminal verdict event plus execution evidence.
1218	// Store.Close is the manual-administration escape hatch when the gate is
1219	// inappropriate.
1220	func (s *Store) CloseWithEvidence(id string, sessionID string, commitSHA string) error {
1221		if err := s.closeWithEvidence(id, sessionID, commitSHA); err != nil {
1222			return err
1223		}
1224		// Externalize events only when the gate actually transitioned the bead
1225		// to closed; rejected closes leave the bead open and inline.
1226		if b, err := s.Get(id); err == nil && b != nil && b.Status == StatusClosed {
1227			if err := s.externalizeEvents(id); err != nil {
1228				return err
1229			}
1230		}
1231		_ = s.RemoveClaimHeartbeat(id)
1232		s.maybeOpportunisticMaintenance()
1233		return nil
1234	}
