1406	// matchesWhere returns true if the bead satisfies all key=value predicates.
1407	// It checks known struct fields first, then falls back to Extra.
1408	func matchesWhere(b Bead, where map[string]string) bool {
1409		for k, v := range where {
1410			var actual string
1411			switch k {
1412			case "id":
1413				actual = b.ID
1414			case "title":
1415				actual = b.Title
1416			case "status":
1417				actual = b.Status
1418			case "issue_type":
1419				actual = b.IssueType
1420			case "owner":
1421				actual = b.Owner
1422			case "assignee":
1423				actual = b.Owner
1424			case "parent":
1425				actual = b.Parent
1426			case "description":
1427				actual = b.Description
1428			case "acceptance":
1429				actual = b.Acceptance
1430			case "notes":
1431				actual = b.Notes
1432			default:
1433				// Fall back to Extra map for unknown/workflow-specific fields
1434				if b.Extra != nil {
1435					if ev, ok := b.Extra[k]; ok {
1436						actual = fmt.Sprintf("%v", ev)
1437					}
1438				}
1439			}
1440			if actual != v {
1441				return false
1442			}
1443		}
1444		return true
1445	}
