1447	type lifecycleQueueEntry struct {
1448		Bead
1449		Decision             LifecycleQueueDecision
1450		UnclosedDepIDs       []string
1451		RetryAfter           time.Time
1452		LastStatus           string
1453		LastDetail           string
1454		ExecutionSkipReason  string
1455		SupersededBy         string
1456		EpicClosureCandidate bool
1457	}
1458	
1459	func (s *Store) classifyLifecycleQueue(beads []Bead, now time.Time) []lifecycleQueueEntry {
1460		statusMap := make(map[string]string)
1461		childCount := make(map[string]int)
1462		openChildCount := make(map[string]int)
1463		for _, b := range beads {
1464			statusMap[b.ID] = b.Status
1465			if b.Parent != "" {
1466				childCount[b.Parent]++
1467				if b.Status != StatusClosed {
1468					openChildCount[b.Parent]++
1469				}
1470			}
1471		}
1472	
1473		entries := make([]lifecycleQueueEntry, 0, len(beads))
1474		for _, b := range beads {
1475			unclosed := unclosedDependencyIDs(b, statusMap)
1476			retryAfter, retryActive := activeRetryCooldown(b, now)
1477			executionEligible, executionEligibleKnown := lifecycleExecutionEligible(b)
1478			supersededBy := lifecycleSupersededBy(b)
1479			entry := lifecycleQueueEntry{
1480				Bead:                 b,
1481				UnclosedDepIDs:       unclosed,
1482				RetryAfter:           retryAfter,
1483				LastStatus:           extraStringVal(b.Extra, ExtraLastStatus),
1484				LastDetail:           extraStringVal(b.Extra, ExtraLastDetail),
1485				ExecutionSkipReason:  extraStringVal(b.Extra, ExtraExecutionReason),
1486				SupersededBy:         supersededBy,
1487				EpicClosureCandidate: isEpicClosureCandidate(b, childCount[b.ID], openChildCount[b.ID]),
1488			}
1489			entry.Decision = EvaluateLifecycleQueue(LifecycleQueueFacts{
1490				Status:                 b.Status,
1491				Dependencies:           lifecycleDependencyStates(b, statusMap),
1492				ClaimFresh:             b.Status == StatusInProgress && !claimLeaseIsStale(s, b.Extra, b.ID),
1493				RetryCooldownActive:    retryActive,
1494				ExecutionEligible:      executionEligible,
1495				ExecutionEligibleKnown: executionEligibleKnown,
1496				SupersededBy:           supersededBy,
1497				EpicContainer:          isOrdinaryEpicContainer(b, childCount[b.ID]),
1498				ExternalBlockerReason:  extraStringVal(b.Extra, ExtraLifecycleExternalBlockerReason),
1499				LegacyLabels:           b.Labels,
1500			})
1501			entries = append(entries, entry)
1502		}
1503		return entries
1504	}
