1506	func lifecycleDependencyStates(b Bead, statusMap map[string]string) []LifecycleDependencyState {
1507		depIDs := b.DepIDs()
1508		if len(depIDs) == 0 {
1509			return nil
1510		}
1511		deps := make([]LifecycleDependencyState, 0, len(depIDs))
1512		for _, depID := range depIDs {
1513			deps = append(deps, LifecycleDependencyState{Status: statusMap[depID]})
1514		}
1515		return deps
1516	}
1517	
1518	func unclosedDependencyIDs(b Bead, statusMap map[string]string) []string {
1519		var unclosed []string
1520		for _, depID := range b.DepIDs() {
1521			if !LifecycleStatusSatisfiesDependency(statusMap[depID]) {
1522				unclosed = append(unclosed, depID)
1523			}
1524		}
1525		return unclosed
1526	}
