1597		DependencyWaiting         []string
1598		ProposedOperatorAttention []string
1599		RetryCooldown             []string
1600		ExternalBlocked           []string
1601		NotEligible               []string
1602		Superseded                []string
1603		Epics                     []string
1604		EpicClosureCandidates     []string
1605		NextRetryAfter            string
