1825	// BlockedAll returns open beads that are currently not runnable, classified
1826	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1827	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1828	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1829	// that is both dep-blocked and cooldown-parked is reported as dependency-
1830	// blocked, because deps are the stronger blocker.
1831	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1832		beads, err := s.ReadAll()
1833		if err != nil {
1834			return nil, err
1835		}
1836	
1837		now := time.Now().UTC()
1838		var entries []BlockedBead
1839		for _, entry := range s.classifyLifecycleQueue(beads, now) {
1840			switch entry.Decision.Bucket {
1841			case LifecycleBucketWaitingDependencies:
1842				entries = append(entries, BlockedBead{
1843					Bead: entry.Bead,
1844					Blocker: Blocker{
1845						Kind:           BlockerKindDependency,
1846						UnclosedDepIDs: entry.UnclosedDepIDs,
1847					},
1848				})
1849			case LifecycleBucketBlockedExternal:
1850				reason := entry.Decision.ExternalBlockerReason
1851				if reason == "" && len(entry.Decision.Issues) > 0 {
1852					reason = entry.Decision.Issues[0].Detail
1853				}
1854				entries = append(entries, BlockedBead{
1855					Bead: entry.Bead,
1856					Blocker: Blocker{
1857						Kind:   BlockerKindBlockedStatus,
1858						Reason: reason,
1859					},
1860				})
1861			case LifecycleBucketProposed:
1862				entries = append(entries, BlockedBead{
1863					Bead: entry.Bead,
1864					Blocker: Blocker{
1865						Kind:   BlockerKindOperatorAttention,
1866						Reason: "status=proposed requires operator attention",
1867					},
1868				})
1869			case LifecycleBucketEpicContainer:
1870				entries = append(entries, BlockedBead{
1871					Bead: entry.Bead,
1872					Blocker: Blocker{
1873						Kind:   BlockerKindEpicOnly,
1874						Reason: "ordinary ddx work skips epic/container beads",
1875					},
1876				})
1877			case LifecycleBucketNotEligible:
1878				entries = append(entries, BlockedBead{
1879					Bead: entry.Bead,
1880					Blocker: Blocker{
1881						Kind:   BlockerKindNotEligible,
1882						Reason: entry.ExecutionSkipReason,
1883					},
1884				})
1885			case LifecycleBucketSuperseded:
1886				entries = append(entries, BlockedBead{
1887					Bead: entry.Bead,
1888					Blocker: Blocker{
1889						Kind:   BlockerKindSuperseded,
1890						Reason: entry.SupersededBy,
1891					},
1892				})
1893			case LifecycleBucketRetryCooldown:
1894				entries = append(entries, BlockedBead{
1895					Bead: entry.Bead,
1896					Blocker: Blocker{
1897						Kind:           BlockerKindRetryCooldown,
1898						NextEligibleAt: entry.RetryAfter.UTC().Format(time.RFC3339),
1899						LastStatus:     entry.LastStatus,
1900						LastDetail:     entry.LastDetail,
1901					},
1902				})
1903			}
1904		}
1905	
1906		sort.SliceStable(entries, func(i, j int) bool {
1907			if entries[i].Priority != entries[j].Priority {
1908				return entries[i].Priority < entries[j].Priority
1909			}
1910			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1911				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1912			}
1913			return entries[i].ID < entries[j].ID
1914		})
1915		return entries, nil
1916	}
