1931	func sortBeadsForQueue(beads []Bead) {
1932		sort.SliceStable(beads, func(i, j int) bool {
1933			if beads[i].Priority != beads[j].Priority {
1934				return beads[i].Priority < beads[j].Priority
1935			}
1936			ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
1937			jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
1938			if iok != jok {
1939				return iok
1940			}
1941			if iok && jok && ir != jr {
1942				return ir < jr
1943			}
1944			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1945				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1946			}
1947			return beads[i].ID < beads[j].ID
1948		})
1949	}
