1951	func parseQueueRank(raw any) (int, bool) {
1952		switch v := raw.(type) {
1953		case int:
1954			return v, true
1955		case int8:
1956			return int(v), true
1957		case int16:
1958			return int(v), true
1959		case int32:
1960			return int(v), true
1961		case int64:
1962			return int(v), true
1963		case uint:
1964			return int(v), true
1965		case uint8:
1966			return int(v), true
1967		case uint16:
1968			return int(v), true
1969		case uint32:
1970			return int(v), true
1971		case uint64:
1972			return int(v), true
1973		case float32:
1974			return int(v), v == float32(int(v))
1975		case float64:
1976			return int(v), v == float64(int(v))
1977		case json.Number:
1978			if n, err := v.Int64(); err == nil {
1979				return int(n), true
1980			}
1981			if f, err := v.Float64(); err == nil {
1982				return int(f), f == float64(int(f))
1983			}
1984		case string:
1985			if n, err := strconv.Atoi(strings.TrimSpace(v)); err == nil {
1986				return n, true
1987			}
1988		}
1989		return 0, false
1990	}
