2010	
2011		// Pull in archive partner so totals survive `bead migrate` — the archive
2012		// only carries closed beads, so Ready/Blocked aren't affected.
2013		seen := make(map[string]bool, len(beads))
2014		all := make([]Bead, 0, len(beads))
2015		for _, b := range beads {
2016			if seen[b.ID] {
2017				continue
2018			}
2019			seen[b.ID] = true
2020			all = append(all, b)
2021		}
2022		if s.Collection == DefaultCollection {
2023			archive := s.archivePartner()
2024			if archived, aerr := archive.ReadAll(); aerr == nil {
2025				for _, b := range archived {
2026					if seen[b.ID] {
2027						continue
2028					}
2029					seen[b.ID] = true
2030					all = append(all, b)
2031				}
2032			}
2033		}
2034	
2035		counts := &StatusCounts{
