2037			Ready:             len(ready),
2038			WorkerReady:       len(workerReady),
2039			NeedsHuman:        len(needsHuman),
2040			OperatorAttention: len(needsHuman),
2041		}
2042		for _, b := range all {
2043			switch b.Status {
2044			case StatusOpen:
2045				counts.Open++
2046			case StatusInProgress:
2047				counts.InProgress++
2048			case StatusClosed:
2049				counts.Closed++
2050			case StatusBlocked:
2051				counts.Blocked++
2052			case StatusProposed:
2053				counts.Proposed++
2054			case StatusCancelled:
2055				counts.Cancelled++
2056			}
2057		}
2058		for _, entry := range s.classifyLifecycleQueue(beads, time.Now().UTC()) {
2059			switch entry.Decision.Bucket {
2060			case LifecycleBucketWaitingDependencies:
2061				counts.DependencyWaiting++
