2069	// DepAdd adds a dependency: id depends on depID.
2070	func (s *Store) DepAdd(id, depID string) error {
2071		return s.WithLock(func() error {
2072			beads, _, err := s.readAllLatestRaw()
2073			if err != nil {
2074				return err
2075			}
2076			var target *Bead
2077			depExists := false
2078			for i := range beads {
2079				if beads[i].ID == id {
2080					target = &beads[i]
2081				}
2082				if beads[i].ID == depID {
2083					depExists = true
2084				}
2085			}
2086			if target == nil {
2087				return fmt.Errorf("bead: not found: %s", id)
2088			}
2089			if !depExists {
2090				return fmt.Errorf("bead: dependency not found: %s", depID)
2091			}
2092			if id == depID {
2093				return fmt.Errorf("bead: cannot depend on self")
2094			}
2095			if target.HasDep(depID) {
2096				return nil // already exists
2097			}
2098	
2099			// Check for circular dependency
2100			depMap := make(map[string][]string)
2101			for _, b := range beads {
2102				depMap[b.ID] = b.DepIDs()
2103			}
2104			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
2105			if hasCycle(depMap, id) {
2106				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
2107			}
2108	
2109			target.AddDep(depID, "blocks")
2110			target.UpdatedAt = time.Now().UTC()
2111			return s.WriteAll(beads)
2112		})
2113	}
