2122	// DepTree returns a text representation of the dependency tree.
2123	func (s *Store) DepTree(rootID string) (string, error) {
2124		beads, err := s.ReadAll()
2125		if err != nil {
2126			return "", err
2127		}
2128		// Pull in archive partner so the tree survives `bead migrate` — closed
2129		// beads stored only in the archive must still appear.
2130		if s.Collection == DefaultCollection {
2131			archive := s.archivePartner()
2132			if archived, aerr := archive.ReadAll(); aerr == nil {
2133				seen := make(map[string]bool, len(beads))
2134				for _, b := range beads {
2135					seen[b.ID] = true
2136				}
2137				for _, b := range archived {
2138					if seen[b.ID] {
2139						continue
2140					}
2141					beads = append(beads, b)
2142				}
2143			}
2144		}
2145		byID := make(map[string]*Bead)
2146		for i := range beads {
2147			byID[beads[i].ID] = &beads[i]
2148		}
2149	
2150		if rootID != "" {
2151			target, ok := byID[rootID]
2152			if !ok {
2153				return "", fmt.Errorf("bead: not found: %s", rootID)
2154			}
2155			var sb strings.Builder
2156			// Walk up: show the dependency chain (what this node depends on)
2157			depChain := s.depChainUp(byID, rootID)
2158			if len(depChain) > 0 {
2159				// Print deps as the tree root(s), with the target as their child
2160				for _, depID := range depChain {
2161					if dep, ok := byID[depID]; ok {
2162						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
2163					}
2164				}
2165			}
2166			// Print the target node
2167			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
2168			// Print dependents (what depends on this node)
2169			var children []string
2170			for _, other := range sortedKeys(byID) {
2171				if byID[other].HasDep(rootID) {
2172					children = append(children, other)
2173				}
2174			}
2175			for _, child := range children {
2176				s.printTree(&sb, byID, child, "  ", true)
2177			}
2178			return sb.String(), nil
2179		}
2180	
2181		// Find roots (beads that have no dependencies themselves)
2182		var roots []string
2183		for _, b := range beads {
2184			if len(b.Dependencies) == 0 {
2185				roots = append(roots, b.ID)
2186			}
2187		}
2188		sort.Strings(roots)
2189	
2190		var sb strings.Builder
2191		for i, root := range roots {
2192			s.printTree(&sb, byID, root, "", i == len(roots)-1)
2193		}
2194		return sb.String(), nil
2195	}
