2197	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
2198		b, ok := byID[id]
2199		if !ok {
2200			return
2201		}
2202	
2203		connector := "├── "
2204		if last {
2205			connector = "└── "
2206		}
2207		if prefix == "" {
2208			connector = ""
2209		}
2210	
2211		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
2212	
2213		// Find beads that depend on this one (children in the tree)
2214		var children []string
2215		for _, other := range sortedKeys(byID) {
2216			if byID[other].HasDep(id) {
2217				children = append(children, other)
2218			}
2219		}
2220	
2221		childPrefix := prefix
2222		if prefix != "" {
2223			if last {
2224				childPrefix += "    "
2225			} else {
2226				childPrefix += "│   "
2227			}
2228		}
2229	
2230		for i, child := range children {
2231			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
2232		}
2233	}
