2264	// detectPrefix derives the bead ID prefix from the repository/directory name,
2265	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
2266	// workingDir is the project root to use for git commands; when empty the
2267	// process working directory is used (legacy behaviour, prone to worktree
2268	// path contamination). Falls back to DefaultPrefix if detection fails.
2269	func detectPrefix(workingDir string) string {
2270		// Try git repo root name first, running from the known project root so
2271		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
2272		// contaminate the prefix with their ephemeral directory names.
2273		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
2274		if out, err := cmd.Output(); err == nil {
2275			root := strings.TrimSpace(string(out))
2276			if root != "" {
2277				return filepath.Base(root)
2278			}
2279		}
2280		// Fall back to the provided working dir, then cwd.
2281		if workingDir != "" {
2282			return filepath.Base(workingDir)
2283		}
2284		if wd, err := os.Getwd(); err == nil {
2285			return filepath.Base(wd)
2286		}
2287		return DefaultPrefix
2288	}
