2331	// hasCycle detects cycles in the dependency graph starting from startID.
2332	func hasCycle(deps map[string][]string, startID string) bool {
2333		visited := make(map[string]bool)
2334		stack := make(map[string]bool)
2335	
2336		var visit func(string) bool
2337		visit = func(id string) bool {
2338			visited[id] = true
2339			stack[id] = true
2340	
2341			for _, dep := range deps[id] {
2342				if !visited[dep] {
2343					if visit(dep) {
2344						return true
2345					}
2346				} else if stack[dep] {
2347					return true
2348				}
2349			}
2350	
2351			stack[id] = false
2352			return false
2353		}
2354	
2355		return visit(startID)
2356	}
2357

2380				report.OutcomeReason = "recoverable"
2381			}
2382			return
2383		}
2384		if report.Status == ExecuteBeadStatusNoEvidenceProduced {
2385			report.OutcomeReason = FailureModeNoEvidenceProduced
2386			return
2387		}
2388		mode := ClassifyFailureMode(report.Status, 1, combined)
2389		if mode == "" || mode == FailureModeUnknown {
2390			return
2391		}
2392		report.OutcomeReason = mode
